// ============================================================================
// Mock Function Utilities
// ============================================================================

type MockCall = {
  type: 'return' | 'throw';
  value: unknown;
};

interface MockImplementation {
  calls: unknown[][];
  results: MockCall[];
  instances: unknown[];
  implementation?: (...args: unknown[]) => unknown;
}

function createMockFunction<T extends (...args: unknown[]) => unknown>(
  implementation?: T
): MockFunction<T> {
  const mockImplementation: MockImplementation = {
    calls: [],
    results: [],
    instances: [],
    implementation,
  };

  const mockFn = (...args: Parameters<T>): ReturnType<T> => {
    mockImplementation.calls.push(args);

    if (mockImplementation.implementation) {
      try {
        const result = mockImplementation.implementation(...args);
        mockImplementation.results.push({ type: 'return', value: result });
        return result as ReturnType<T>;
      } catch (error) {
        mockImplementation.results.push({ type: 'throw', value: error });
        throw error;
      }
    }

    mockImplementation.results.push({ type: 'return', value: undefined });
    return undefined as ReturnType<T>;
  };

  mockFn.mock = mockImplementation;

  mockFn.mockClear = () => {
    mockImplementation.calls = [];
    mockImplementation.results = [];
  };

  mockFn.mockReset = () => {
    mockImplementation.calls = [];
    mockImplementation.results = [];
    mockImplementation.instances = [];
    mockImplementation.implementation = undefined;
  };

  mockFn.mockRestore = () => {
    mockImplementation.implementation = undefined;
  };

  mockFn.mockImplementation = (fn: T): MockFunction<T> => {
    mockImplementation.implementation = fn;
    return mockFn;
  };

  mockFn.mockReturnValue = (value: ReturnType<T>): MockFunction<T> => {
    mockImplementation.implementation = () => value as ReturnType<T>;
    return mockFn;
  };

  mockFn.mockResolvedValue = <R>(
    value: R
  ): MockFunction<(...args: unknown[]) => Promise<R>> => {
    mockImplementation.implementation = async () => value;
    return mockFn as MockFunction<(...args: unknown[]) => Promise<R>>;
  };

  return mockFn;
}

function createSpyOn<T extends object, K extends keyof T>(
  obj: T,
  method: K
): MockFunction {
  const originalMethod = obj[method];
  const mock = createMockFunction(originalMethod as (...args: unknown[]) => unknown);

  obj[method] = ((...args: unknown[]) => {
    try {
      const result = mock(...args);
      return result;
    } catch (error) {
      throw error;
    }
  }) as T[K];

  mock.mockRestore = () => {
    obj[method] = originalMethod as T[K];
  };

  return mock;
}

// ============================================================================
// Assertion Utilities
// ============================================================================

class AssertionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'AssertionError';
  }
}

function deepEqual(actual: unknown, expected: unknown, visited = new WeakSet()): boolean {
  if (actual === expected) return true;
  if (actual === null || expected === null) return false;
  if (typeof actual !== typeof expected) return false;

  if (typeof actual !== 'object' || typeof expected !== 'object') {
    return false;
  }

  if (visited.has(actual as object)) return true;
  visited.add(actual as object);

  if (Array.isArray(actual) !== Array.isArray(expected)) return false;

  if (Array.isArray(actual) && Array.isArray(expected)) {
    if (actual.length !== expected.length) return false;
    for (let i = 0; i < actual.length; i++) {
      if (!deepEqual(actual[i], expected[i], visited)) return false;
    }
    return true;
  }

  const actualObj = actual as Record<string, unknown>;
  const expectedObj = expected as Record<string, unknown>;

  const actualKeys = Object.keys(actualObj);
  const expectedKeys = Object.keys(expectedObj);

  if (actualKeys.length !== expectedKeys.length) return false;

  for (const key of actualKeys) {
    if (!expectedKeys.includes(key)) return false;
    if (!deepEqual(actualObj[key], expectedObj[key], visited)) return false;
  }

  return true;
}

function createMatchers<T>(actual: T, negate: boolean = false): AssertionMatchers<T> {
  const pass = (result: boolean) => {
    if (negate) return !result;
    return result;
  };

  const formatValue = (val: unknown): string => {
    if (typeof val === 'string') return `"${val}"`;
    if (val === null) return 'null';
    if (val === undefined) return 'undefined';
    if (typeof val === 'object') return JSON.stringify(val, null, 2);
    return String(val);
  };

  const matchers: AssertionMatchers<T> = {
    toBe(expected: T): void {
      if (!pass(actual === expected)) {
        throw new AssertionError(
          `Expected ${formatValue(actual)} to ${negate ? 'not ' : ''}be ${formatValue(expected)}`
        );
      }
    },

    toEqual(expected: T): void {
      if (!pass(deepEqual(actual, expected))) {
        throw new AssertionError(
          `Expected ${formatValue(actual)} to ${negate ? 'not ' : ''}equal ${formatValue(expected)}`
        );
      }
    },

    toBeNull(): void {
      if (!pass(actual === null)) {
        throw new AssertionError(
          `Expected ${formatValue(actual)} to ${negate ? 'not ' : ''}be null`
        );
      }
    },

    toBeUndefined(): void {
      if (!pass(actual === undefined)) {
        throw new AssertionError(
          `Expected ${formatValue(actual)} to ${negate ? 'not ' : ''}be undefined`
        );
      }
    },

    toBeDefined(): void {
      if (!pass(actual !== undefined)) {
        throw new AssertionError(
          `Expected value to ${negate ? 'not ' : ''}be defined`
        );
      }
    },

    toBeTruthy(): void {
      if (!pass(!!actual)) {
        throw new AssertionError(
          `Expected ${formatValue(actual)} to ${negate ? 'not ' : ''}be truthy`
        );
      }
    },

    toBeFalsy(): void {
      if (!pass(!actual)) {
        throw new AssertionError(
          `Expected ${formatValue(actual)} to ${negate ? 'not ' : ''}be falsy`
        );
      }
    },

    toBeGreaterThan(expected: number): void {
      if (!pass(typeof actual === 'number' && actual > expected)) {
        throw new AssertionError(
          `Expected ${formatValue(actual)} to ${negate ? 'not ' : ''}be greater than ${formatValue(expected)}`
        );
      }
    },

    toBeGreaterThanOrEqual(expected: number): void {
      if (!pass(typeof actual === 'number' && actual >= expected)) {
        throw new AssertionError(
          `Expected ${formatValue(actual)} to ${negate ? 'not ' : ''}be greater than or equal to ${formatValue(expected)}`
        );
      }
    },

    toBeLessThan(expected: number): void {
      if (!pass(typeof actual === 'number' && actual < expected)) {
        throw new AssertionError(
          `Expected ${formatValue(actual)} to ${negate ? 'not ' : ''}be less than ${formatValue(expected)}`
        );
      }
    },

    toBeLessThanOrEqual(expected: number): void {
      if (!pass(typeof actual === 'number' && actual <= expected)) {
        throw new AssertionError(
          `Expected ${formatValue(actual)} to ${negate ? 'not ' : ''}be less than or equal to ${formatValue(expected)}`
        );
      }
    },

    toContain(expected: unknown): void {
      let contains = false;
      if (Array.isArray(actual)) {
        contains = actual.some((item) => deepEqual(item, expected));
      } else if (typeof actual === 'string') {
        contains = actual.includes(String(expected));
      }
      if (!pass(contains)) {
        throw new AssertionError(
          `Expected ${formatValue(actual)} to ${negate ? 'not ' : ''}contain ${formatValue(expected)}`
        );
      }
    },

    toHaveLength(expected: number): void {
      const length = Array.isArray(actual) || typeof actual === 'string' 
        ? actual.length 
        : (actual && typeof actual === 'object' ? Object.keys(actual).length : undefined);
      if (!pass(length === expected)) {
        throw new AssertionError(
          `Expected ${formatValue(actual)} to ${negate ? 'not ' : ''}have length ${formatValue(expected)}`
        );
      }
    },

    toMatch(expected: RegExp | string): void {
      const actualStr = String(actual);
      let matches: boolean;
      if (expected instanceof RegExp) {
        matches = expected.test(actualStr);
      } else {
        matches = actualStr.includes(expected);
      }
      if (!pass(matches)) {
        throw new AssertionError(
          `Expected ${formatValue(actual)} to ${negate ? 'not ' : ''}match ${formatValue(expected)}`
        );
      }
    },

    toThrow(expected?: string | RegExp): void {
      let threw = false;
      let thrownError: Error | undefined;

      if (actual instanceof Function) {
        try {
          actual();
        } catch (error) {
          threw = true;
          thrownError = error as Error;
        }
      }

      if (!pass(threw)) {
        throw new AssertionError(
          `Expected function to ${negate ? 'not ' : ''}throw`
        );
      }

      if (expected && thrownError) {
        const message = thrownError.message || '';
        let matches: boolean;
        if (expected instanceof RegExp) {
          matches = expected.test(message);
        } else {
          matches = message.includes(expected);
        }
        if (!pass(matches)) {
          throw new AssertionError(
            `Expected error message to ${negate ? 'not ' : ''}match ${formatValue(expected)}, but got "${message}"`
          );
        }
      }
    },

    not: createMatchers(actual, !negate) as AssertionMatchers<T>,
  };

  return matchers;
}

export const expect: Assertion = <T>(actual: T): AssertionMatchers<T> => {
  return createMatchers(actual);
};

