const randomStringChars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';

const createRandomString = (length: number = 10): string => {
  let result = '';
  for (let i = 0; i < length; i++) {
    result += randomStringChars.charAt(
      Math.floor(Math.random() * randomStringChars.length)
    );
  }
  return result;
};

const createRandomNumber = (min: number = 0, max: number = 100): number => {
  return Math.floor(Math.random() * (max - min + 1)) + min;
};

const createRandomBoolean = (): boolean => {
  return Math.random() > 0.5;
};

const createRandomDate = (start: Date = new Date(0), end: Date = new Date()): Date => {
  return new Date(start.getTime() + Math.random() * (end.getTime() - start.getTime()));
};

const createRandomArray = <T>(generator: () => T, count?: number): T[] => {
  const length = count ?? createRandomNumber(1, 10);
  return Array.from({ length }, generator);
};

const createRandomObject = <T extends Record<string, unknown>>(template: T): T => {
  const result: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(template)) {
    if (typeof value === 'string') {
      result[key] = createRandomString(createRandomNumber(5, 20));
    } else if (typeof value === 'number') {
      result[key] = createRandomNumber();
    } else if (typeof value === 'boolean') {
      result[key] = createRandomBoolean();
    } else if (value instanceof Date) {
      result[key] = createRandomDate();
    } else if (Array.isArray(value)) {
      result[key] = createRandomArray(() => createRandomString());
    } else {
      result[key] = value;
    }
  }
  return result as T;
};

