// ============================================================================
// Timer Utilities
// ============================================================================

export const sleep = (ms: number): Promise<void> => {
  return new Promise((resolve) => setTimeout(resolve, ms));
};

export const timeout = async <T>(
  promise: Promise<T>,
  ms: number,
  errorMessage: string = 'Operation timed out'
): Promise<T> => {
  let timeoutId: ReturnType<typeof setTimeout>;

  const timeoutPromise = new Promise<never>((_, reject) => {
    timeoutId = setTimeout(() => {
      reject(new Error(errorMessage));
    }, ms);
  });

  try {
    const result = await Promise.race([promise, timeoutPromise]);
    clearTimeout(timeoutId!);
    return result;
  } catch (error) {
    clearTimeout(timeoutId!);
    throw error;
  }
};

export const waitFor = async (
  condition: () => boolean | Promise<boolean>,
  options: { timeout?: number; interval?: number } = {}
): Promise<void> => {
  const { timeout: timeoutMs = 5000, interval = 50 } = options;
  const startTime = Date.now();

  while (Date.now() - startTime < timeoutMs) {
    const result = await Promise.resolve(condition());
    if (result) return;
    await sleep(interval);
  }

  throw new Error(`waitFor timed out after ${timeoutMs}ms`);
};

export const debounce = <T extends (...args: unknown[]) => unknown>(
  fn: T,
  ms: number
): ((...args: Parameters<T>) => void) => {
  let timeoutId: ReturnType<typeof setTimeout> | null = null;

  return (...args: Parameters<T>): void => {
    if (timeoutId) {
      clearTimeout(timeoutId);
    }
    timeoutId = setTimeout(() => {
      fn(...args);
      timeoutId = null;
    }, ms);
  };
};

export const throttle = <T extends (...args: unknown[]) => unknown>(
  fn: T,
  ms: number
): ((...args: Parameters<T>) => void) => {
  let lastCall = 0;
  let timeoutId: ReturnType<typeof setTimeout> | null = null;

  return (...args: Parameters<T>): void => {
    const now = Date.now();
    const remaining = ms - (now - lastCall);

    if (remaining <= 0) {
      if (timeoutId) {
        clearTimeout(timeoutId);
        timeoutId = null;
      }
      lastCall = now;
      fn(...args);
    } else if (!timeoutId) {
      timeoutId = setTimeout(() => {
        lastCall = Date.now();
        timeoutId = null;
        fn(...args);
      }, remaining);
    }
  };
};

export const timerUtils: TimerUtils = {
  sleep,
  timeout,
  waitFor,
  debounce,
  throttle,
};

// ============================================================================
// Comparison Utilities
// ============================================================================

export const deepCompare = (
  actual: unknown,
  expected: unknown,
  options: DeepCompareOptions = {},
  path: string = ''
): ComparisonResult => {
  const { strict = true, ignoreKeys = [], ignoreUndefined = false, maxDepth } = options;
  const differences: ComparisonDifference[] = [];

  if (maxDepth !== undefined && maxDepth < 0) {
    return { equal: true, differences: [] };
  }

  if (actual === expected) {
    return { equal: true, differences: [] };
  }

  if (actual === null || expected === null) {
    if (actual !== expected) {
      differences.push({
        path,
        expected,
        actual,
        type: 'changed',
      });
    }
    return { equal: false, differences };
  }

  if (typeof actual !== typeof expected) {
    differences.push({
      path,
      expected,
      actual,
      type: 'changed',
    });
    return { equal: false, differences };
  }

  if (typeof actual !== 'object') {
    if (actual !== expected) {
      differences.push({
        path,
        expected,
        actual,
        type: 'changed',
      });
    }
    return { equal: false, differences };
  }

  const actualObj = actual as Record<string, unknown>;
  const expectedObj = expected as Record<string, unknown>;

  const actualKeys = Object.keys(actualObj).filter((k) => !ignoreKeys.includes(k));
  const expectedKeys = Object.keys(expectedObj).filter((k) => !ignoreKeys.includes(k));

  const allKeys = new Set([...actualKeys, ...expectedKeys]);

  for (const key of allKeys) {
    const currentPath = path ? `${path}.${key}` : key;

    if (!(key in actualObj)) {
      if (!(key in expectedObj)) continue;
      if (ignoreUndefined && expectedObj[key] === undefined) continue;
      differences.push({
        path: currentPath,
        expected: expectedObj[key],
        actual: undefined,
        type: 'added',
      });
      continue;
    }

    if (!(key in expectedObj)) {
      if (ignoreUndefined && actualObj[key] === undefined) continue;
      differences.push({
        path: currentPath,
        expected: undefined,
        actual: actualObj[key],
        type: 'removed',
      });
      continue;
    }

    if (ignoreUndefined && actualObj[key] === undefined && expectedObj[key] === undefined) {
      continue;
    }

    const valueActual = actualObj[key];
    const valueExpected = expectedObj[key];

    if (typeof valueActual !== typeof valueExpected) {
      differences.push({
        path: currentPath,
        expected: valueExpected,
        actual: valueActual,
        type: 'changed',
      });
      continue;
    }

    if (typeof valueActual === 'object' && valueActual !== null && valueExpected !== null) {
      const nestedResult = deepCompare(valueActual, valueExpected, {
        ...options,
        maxDepth: maxDepth !== undefined ? maxDepth - 1 : undefined,
      }, currentPath);

      differences.push(...nestedResult.differences);
    } else if (strict ? valueActual !== valueExpected : valueActual != valueExpected) {
      differences.push({
        path: currentPath,
        expected: valueExpected,
        actual: valueActual,
        type: 'changed',
      });
    }
  }

  return { equal: differences.length === 0, differences };
};

// ============================================================================
// Logger
// ============================================================================

type LogLevel = 'info' | 'warn' | 'error' | 'debug' | 'trace';

interface LogEntry {
  level: LogLevel;
  message: string;
  data?: Record<string, unknown>;
  timestamp: string;
}

const logs: LogEntry[] = [];
const maxLogs = 1000;

const log = (level: LogLevel, message: string, data?: Record<string, unknown>): void => {
  const entry: LogEntry = {
    level,
    message,
    data,
    timestamp: formatTimestamp(),
  };

  logs.push(entry);
  if (logs.length > maxLogs) {
    logs.shift();
  }

  const prefix = `[${level.toUpperCase()}]`;
  const logMessage = data ? `${prefix} ${message} ${JSON.stringify(data)}` : `${prefix} ${message}`;

  switch (level) {
    case 'error':
      console.error(logMessage);
      break;
    case 'warn':
      console.warn(logMessage);
      break;
    case 'debug':
      if (process.env.NODE_ENV !== 'production') {
        console.debug(logMessage);
      }
      break;
    case 'trace':
      if (process.env.NODE_ENV !== 'production') {
        console.log(logMessage);
      }
      break;
    default:
      console.log(logMessage);
  }
};

export const logger: Logger = {
  info: (message: string, data?: Record<string, unknown>) => log('info', message, data),
  warn: (message: string, data?: Record<string, unknown>) => log('warn', message, data),
  error: (message: string, data?: Record<string, unknown>) => log('error', message, data),
  debug: (message: string, data?: Record<string, unknown>) => log('debug', message, data),
  trace: (message: string, data?: Record<string, unknown>) => log('trace', message, data),
};

export const getLogs = (level?: LogLevel): LogEntry[] => {
  if (level) {
    return logs.filter((entry) => entry.level === level);
  }
  return [...logs];
};

export const clearLogs = (): void => {
  logs.length = 0;
};

