type LifecycleHook = () => Promise<void> | void;

interface SuiteContext {
  beforeAll: LifecycleHook[];
  afterAll: LifecycleHook[];
  beforeEach: LifecycleHook[];
  afterEach: LifecycleHook[];
  tests: Array<{
    name: string;
    fn: () => Promise<void> | void;
    timeout?: number;
    skip?: boolean;
    only?: boolean;
  }>;
  currentTest?: string;
}

const suiteContexts: Map<string, SuiteContext> = new Map();
let currentSuite: SuiteContext | null = null;

export const describe = (name: string, fn: () => void): void => {
  const context: SuiteContext = {
    beforeAll: [],
    afterAll: [],
    beforeEach: [],
    afterEach: [],
    tests: [],
  };

  const previousSuite = currentSuite;
  currentSuite = context;
  suiteContexts.set(name, context);

  try {
    fn();
  } finally {
    currentSuite = previousSuite;
  }
};

export const it = (
  name: string,
  fn: () => Promise<void> | void,
  timeout?: number
): void => {
  if (currentSuite) {
    currentSuite.tests.push({ name, fn, timeout });
  }
};

