// ============================================================================
// Test Runner
// ============================================================================

type TestStatus = 'pending' | 'running' | 'passed' | 'failed' | 'skipped';

const runLifecycleHooks = async (hooks: LifecycleHook[]): Promise<void> => {
  for (const hook of hooks) {
    await hook();
  }
};

const runTest = async (
  testFn: () => Promise<void> | void,
  timeout?: number,
  setupHooks?: LifecycleHook[],
  teardownHooks?: LifecycleHook[]
): Promise<{ passed: boolean; error?: Error; durationMs: number }> => {
  const startTime = Date.now();

  try {
    await runLifecycleHooks(setupHooks || []);

    const timeoutPromise = timeout
      ? new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error(`Test timed out after ${timeout}ms`)), timeout)
        )
      : new Promise<never>((_, reject) => 
          setTimeout(() => reject(new Error('Test timed out')), 30000)
        );

    await Promise.race([Promise.resolve(testFn()), timeoutPromise]);

    await runLifecycleHooks(teardownHooks || []);

    return { passed: true, durationMs: Date.now() - startTime };
  } catch (error) {
    await runLifecycleHooks(teardownHooks || []);
    return { 
      passed: false, 
      error: error instanceof Error ? error : new Error(String(error)),
      durationMs: Date.now() - startTime 
    };
  }
};

const createReporter = (type: TestReporterType): TestReporter => {
  switch (type) {
    case 'spec':
      return createSpecReporter();
    case 'dot':
      return createDotReporter();
    case 'json':
      return createJsonReporter();
    default:
      return createSpecReporter();
  }
};

const createSpecReporter = (): TestReporter => ({
  onStart: (totalSuites: number) => {
    console.log(`\nRunning ${totalSuites} test suite(s)...\n`);
  },
  onSuiteStart: (suite: TestSuiteConfig) => {
    console.log(`\n${suite.name}`);
    console.log('='.repeat(suite.name.length));
  },
  onTestResult: (result: TestResult) => {
    const statusIcon = result.status === 'passed' ? '✓' : result.status === 'skipped' ? '○' : '✗';
    const statusText = result.status === 'passed' ? '' : result.error ? `\n  ${result.error}` : '';
    console.log(`  ${statusIcon} ${result.testName}${statusText}`);
  },
  onSuiteEnd: (result: TestSuiteResult) => {
    const passed = result.passedTests;
    const failed = result.failedTests;
    const skipped = result.skippedTests;
    const total = result.totalTests;

    console.log(`\n  ${passed}/${total} passed, ${failed} failed, ${skipped} skipped (${formatDuration(result.durationMs)})`);
  },
  onEnd: (summary: TestRunSummary) => {
    const statusEmoji = summary.status === 'passed' ? '🎉' : summary.status === 'failed' ? '❌' : '💥';
    console.log(`\n${statusEmoji} Test run complete: ${summary.passedTests}/${summary.totalTests} passed (${formatDuration(summary.totalDurationMs)})\n`);
  },
});

const createDotReporter = (): TestReporter => {
  let dots: string[] = [];

  return {
    onStart: () => { dots = []; },
    onSuiteStart: () => {},
    onTestResult: (result: TestResult) => {
      if (result.status === 'passed') {
        dots.push('.');
      } else if (result.status === 'skipped') {
        dots.push('○');
      } else {
        dots.push('✗');
      }
      if (dots.length % 80 === 0) {
        console.log('\n');
      }
    },
    onSuiteEnd: () => {},
    onEnd: (summary: TestRunSummary) => {
      console.log('\n');
    },
  };
};

const createJsonReporter = (): TestReporter => {
  const results: TestSuiteResult[] = [];

  return {
    onStart: () => { results.length = 0; },
    onSuiteStart: () => {},
    onTestResult: () => {},
    onSuiteEnd: (result: TestSuiteResult) => {
      results.push(result);
    },
    onEnd: (summary: TestRunSummary) => {
      console.log(JSON.stringify({ ...summary, results }, null, 2));
    },
  };
};

export const runTests = async (
  options: TestRunnerOptions
): Promise<TestRunSummary> => {
  const {
    suites,
    parallel = false,
    maxConcurrency = 4,
    timeout = 30000,
    retries = 0,
    retryDelay = 1000,
    failFast = false,
    bail = false,
    verbose = false,
    reporter: reporterType = 'spec',
  } = options;

  const reporter = createReporter(reporterType);
  const startTime = new Date();

  reporter.onStart(suites.length);

  const suiteResults: TestSuiteResult[] = [];
  let totalPassed = 0;
  let totalFailed = 0;
  let totalSkipped = 0;

  const runSuite = async (suiteConfig: TestSuiteConfig): Promise<TestSuiteResult> => {
    const suiteStartTime = new Date();
    const context = suiteContexts.get(suiteConfig.name);

    if (!context) {
      return {
        suiteName: suiteConfig.name,
        filePath: suiteConfig.filePath,
        status: 'passed' as TestStatus,
        totalTests: 0,
        passedTests: 0,
        failedTests: 0,
        skippedTests: 0,
        durationMs: 0,
        results: [],
        startedAt: suiteStartTime.toISOString(),
        completedAt: new Date().toISOString(),
      };
    }

    reporter.onSuiteStart(suiteConfig);

    await runLifecycleHooks(suiteConfig.beforeAll || []);
    await runLifecycleHooks(context.beforeAll);

    const results: TestResult[] = [];
    let passedTests = 0;
    let failedTests = 0;
    let skippedTests = 0;
    let suiteStatus: TestStatus = 'passed';

    for (const test of context.tests) {
      if (test.skip) {
        skippedTests++;
        results.push({
          testId: generateId(),
          testName: test.name,
          suiteName: suiteConfig.name,
          status: 'skipped' as TestStatus,
          durationMs: 0,
          error: null,
          stackTrace: null,
          startedAt: new Date().toISOString(),
          completedAt: new Date().toISOString(),
        });
        reporter.onTestResult(results[results.length - 1]);
        continue;
      }

      let attempt = 0;
      let testResult: { passed: boolean; error?: Error; durationMs: number };

      do {
        testResult = await runTest(
          test.fn,
          test.timeout || timeout,
          [...(suiteConfig.beforeEach || []), ...context.beforeEach],
          [...context.afterEach, ...(suiteConfig.afterEach || [])]
        );

        if (!testResult.passed) {
          attempt++;
          if (attempt < retries && testResult.error) {
            await sleep(retryDelay);
          }
        }
      } while (!testResult.passed && attempt < retries);

      const status: TestStatus = testResult.passed ? 'passed' : 'failed';

      if (status === 'passed') {
        passedTests++;
      } else if (test.skip) {
        skippedTests++;
      } else {
        failedTests++;
        if (failFast) break;
      }

      results.push({
        testId: generateId(),
        testName: test.name,
        suiteName: suiteConfig.name,
        status,
        durationMs: testResult.durationMs,
        error: testResult.error?.message || null,
        stackTrace: testResult.error?.stack || null,
        startedAt: new Date().toISOString(),
        completedAt: new Date().toISOString(),
      });

      reporter.onTestResult(results[results.length - 1]);

      if (bail && failedTests > 0) break;
    }

    await runLifecycleHooks(context.afterEach);
    await runLifecycleHooks(suiteConfig.afterEach || []);
    await runLifecycleHooks(context.afterAll);
    await runLifecycleHooks(suiteConfig.afterAll || []);

    if (failedTests > 0) suiteStatus = 'failed';
    else if (skippedTests === context.tests.length) suiteStatus = 'skipped';

    const suiteResult: TestSuiteResult = {
      suiteName: suiteConfig.name,
      filePath: suiteConfig.filePath,
      status: suiteStatus,
      totalTests: context.tests.length,
      passedTests,
      failedTests,
      skippedTests,
      durationMs: Date.now() - suiteStartTime.getTime(),
      results,
      startedAt: suiteStartTime.toISOString(),
      completedAt: new Date().toISOString(),
    };

    reporter.onSuiteEnd(suiteResult);

    return suiteResult;
  };

  if (parallel) {
    const chunks: TestSuiteConfig[][] = [];
    for (let i = 0; i < suites.length; i += maxConcurrency) {
      chunks.push(suites.slice(i, i + maxConcurrency));
    }

    for (const chunk of chunks) {
      const chunkResults = await Promise.all(chunk.map(runSuite));
      suiteResults.push(...chunkResults);

      if (bail && chunkResults.some((r) => r.failedTests > 0)) {
        break;
      }
    }
  } else {
    for (const suite of suites) {
      const result = await runSuite(suite);
      suiteResults.push(result);

      if (bail && result.failedTests > 0) {
        break;
      }
    }
  }

  for (const result of suiteResults) {
    totalPassed += result.passedTests;
    totalFailed += result.failedTests;
    totalSkipped += result.skippedTests;
  }

  const totalTests = totalPassed + totalFailed + totalSkipped;
  const summary: TestRunSummary = {
    totalSuites: suiteResults.length,
    totalTests,
    passedTests: totalPassed,
    failedTests: totalFailed,
    skippedTests: totalSkipped,
    totalDurationMs: Date.now() - startTime.getTime(),
    startTime: startTime.toISOString(),
    endTime: new Date().toISOString(),
    status: totalFailed === 0 ? 'passed' : totalPassed === 0 ? 'error' : 'failed',
  };

  reporter.onEnd(summary);

  return summary;
};

