// [COMMON]
export interface ApiError {
  code: string;
  message: string;
  details?: Record<string, unknown>;
}

export interface PaginationParams {
  page?: number;
  limit?: number;
}

export interface PaginatedResponse<T> {
  items: T[];
  total: number;
  page: number;
  limit: number;
  totalPages: number;
}

export interface Timestamped {
  createdAt: string;
  updatedAt: string;
}

export interface ApiResponse<T> {
  data: T;
  success: boolean;
  message?: string;
}

export type HttpMethod = 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE';

export type TestStatus = 'passed' | 'failed' | 'running' | 'skipped' | 'error';

export type RandomDataType = 'string' | 'number' | 'boolean' | 'object' | 'array';

// [FILE: src/services/api.ts]
export interface ApiServiceConfig {
  baseUrl: string;
  timeout?: number;
  headers?: Record<string, string>;
  withCredentials?: boolean;
}

export interface HealthCheckResponse {
  status: 'ok' | 'degraded' | 'down';
  timestamp: string;
  uptime: number;
  version?: string;
}

export interface EchoRequest {
  payload: unknown;
  metadata?: {
    timestamp?: string;
    source?: string;
  };
}

export interface EchoResponse {
  echoed: unknown;
  receivedAt: string;
  processingTimeMs?: number;
}

export interface RandomDataParams {
  type?: RandomDataType;
  count?: number;
}

export interface RandomDataResponse {
  type: RandomDataType;
  data: unknown[];
  count: number;
}

export interface ValidationRequest {
  schema: Record<string, unknown>;
  data: Record<string, unknown>;
  strict?: boolean;
}

export interface ValidationResponse {
  valid: boolean;
  errors: ValidationErrorItem[];
}

export interface ValidationErrorItem {
  path: string;
  message: string;
  code?: string;
}

export interface BenchmarkRequest {
  name: string;
  iterations: number;
  payload?: Record<string, unknown>;
  concurrency?: number;
}

export interface BenchmarkResults {
  totalTimeMs: number;
  averageTimeMs: number;
  minTimeMs?: number;
  maxTimeMs?: number;
  opsPerSecond: number;
  iterations: number;
}

export interface BenchmarkResponse {
  name: string;
  results: BenchmarkResults;
}

export interface MockEndpointCreate {
  method: HttpMethod;
  path: string;
  response: {
    statusCode?: number;
    body: Record<string, unknown>;
    headers?: Record<string, string>;
    delay?: number;
  };
  description?: string;
}

export interface MockEndpointResponse {
  id: string;
  method: HttpMethod;
  path: string;
  createdAt: string;
  callCount: number;
}

export interface FileCoverage {
  path: string;
  coveragePercentage: number;
  totalLines: number;
  coveredLines: number;
  uncoveredLines?: number[];
}

export interface CoverageReport {
  summary: {
    totalLines: number;
    coveredLines: number;
    coveragePercentage: number;
    totalBranches?: number;
    coveredBranches?: number;
    branchCoverage?: number;
  };
  files: FileCoverage[];
  generatedAt: string;
}

export interface TestRun {
  id: string;
  suite: string;
  status: TestStatus;
  startedAt: string;
  completedAt?: string | null;
  durationMs?: number;
  totalTests?: number;
  passedTests?: number;
  failedTests?: number;
  errorMessage?: string | null;
}

export interface TestHistoryResponse extends PaginatedResponse<TestRun> {}

export interface TestSuite {
  name: string;
  filePath: string;
  description?: string;
  testCount: number;
  tags?: string[];
  lastRun?: string | null;
  lastStatus?: 'passed' | 'failed' | 'never_run' | null;
}

export interface TestSuitesResponse {
  suites: TestSuite[];
  total: number;
}

export interface RequestInterceptor {
  (config: RequestInit & { url: string }): RequestInit & { url: string };
}

export interface ResponseInterceptor {
  <T>(response: T): T;
}

export interface ApiClient {
  get<T>(path: string, params?: Record<string, unknown>): Promise<ApiResponse<T>>;
  post<T>(path: string, body?: unknown): Promise<ApiResponse<T>>;
  put<T>(path: string, body?: unknown): Promise<ApiResponse<T>>;
  patch<T>(path: string, body?: unknown): Promise<ApiResponse<T>>;
  delete<T>(path: string): Promise<ApiResponse<T>>;
  setBaseUrl(url: string): void;
  setHeaders(headers: Record<string, string>): void;
  addRequestInterceptor(interceptor: RequestInterceptor): void;
  addResponseInterceptor(interceptor: ResponseInterceptor): void;
}

