export type TestReporterType = 'spec' | 'dot' | 'json' | 'junit' | 'tap' | 'custom';

export interface TestReporter {
  onStart: (totalSuites: number) => void;
  onSuiteStart: (suite: TestSuiteConfig) => void;
  onTestResult: (result: TestResult) => void;
  onSuiteEnd: (result: TestSuiteResult) => void;
