}

export interface TestRunSummary {
  totalSuites: number;
  totalTests: number;
  passedTests: number;
  failedTests: number;
  skippedTests: number;
  totalDurationMs: number;
  startTime: string;
  endTime: string;
  status: 'passed' | 'failed' | 'error';
}

export interface MockFunction<T extends (...args: unknown[]) => unknown = (...args: unknown[]) => unknown> {
  (...args: Parameters<T>): ReturnType<T>;
  mock: {
    calls: unknown[][];
    results: { type: 'return' | 'throw'; value: unknown }[];
    instances: unknown[];
    implementation?: T;
  };
  mockClear: () => void;
  mockReset: () => void;
  mockRestore: () => void;
  mockImplementation: (fn: T) => MockFunction<T>;
  mockReturnValue: (value: ReturnType<T>) => MockFunction<T>;
  mockResolvedValue: <R>(value: R) => MockFunction<(...args: unknown[]) => Promise<R>>;
}

export interface AssertionMatchers<T> {
  toBe(expected: T): void;
  toEqual(expected: T): void;
  toBeNull(): void;
  toBeUndefined(): void;
  toBeDefined(): void;
  toBeTruthy(): void;
  toBeFalsy(): void;
  toBeGreaterThan(expected: number): void;
  toBeGreaterThanOrEqual(expected: number): void;
  toBeLessThan(expected: number): void;
  toBeLessThanOrEqual(expected: number): void;
  toContain(expected: unknown): void;
  toHaveLength(expected: number): void;
  toMatch(expected: RegExp | string): void;
  toThrow(expected?: string | RegExp): void;
  not: AssertionMatchers<T>;
}

export interface Assertion {
  <T>(actual: T): AssertionMatchers<T>;
}

export interface TestUtilities {
  describe: (name: string, fn: () => void) => void;
  it: (name: string, fn: () => Promise<void> | void, timeout?: number) => void;
  test: (name: string, fn: () => Promise<void> | void, timeout?: number) => void;
  expect: Assertion;
  beforeEach: (fn: () => Promise<void> | void) => void;
  afterEach: (fn: () => Promise<void> | void) => void;
  beforeAll: (fn: () => Promise<void> | void) => void;
  afterAll: (fn: () => Promise<void> | void) => void;
  jest: {
    fn: <T extends (...args: unknown[]) => unknown>(implementation?: T) => MockFunction<T>;
    spyOn: <T extends object, K extends keyof T>(obj: T, method: K) => MockFunction;
    clearAllMocks: () => void;
    resetAllMocks: () => void;
    useFakeTimers: (config?: { now?: number; advanceTimers?: boolean }) => void;
    useRealTimers: () => void;
    advanceTimersByTime: (ms: number) => void;
    runAllTimers: () => void;
  };
  vi: {
    fn: <T extends (...args: unknown[]) => unknown>(implementation?: T) => MockFunction<T>;
    spyOn: <T extends object, K extends keyof T>(obj: T, method: K) => MockFunction;
    clearAllMocks: () => void;
    resetAllMocks: () => void;
    useFakeTimers: (config?: { now?: number; advanceTimers?: boolean }) => void;
    useRealTimers: () => void;
    advanceTimersByTime: (ms: number) => void;
    runAllTimers: () => void;
  };
}

export interface TestDataFactory {
  createUser: (overrides?: Partial<UserFixture>) => UserFixture;
  createPost: (overrides?: Partial<PostFixture>) => PostFixture;
  createComment: (overrides?: Partial<CommentFixture>) => CommentFixture;
  createRandomString: (length?: number) => string;
  createRandomNumber: (min?: number, max?: number) => number;
  createRandomBoolean: () => boolean;
  createRandomDate: (start?: Date, end?: Date) => Date;
  createRandomArray: <T>(generator: () => T, count?: number) => T[];
  createRandomObject: <T extends Record<string, unknown>>(template: T) => T;
}

