export interface DelayOptions {
  ms: number;
  variable?: boolean;
}

export interface TimerUtils {
  sleep: (ms: number) => Promise<void>;
  timeout: <T>(promise: Promise<T>, ms: number, errorMessage?: string) => Promise<T>;
  waitFor: (condition: () => boolean | Promise<boolean>, options?: { timeout?: number; interval?: number }) => Promise<void>;
  debounce: <T extends (...args: unknown[]) => unknown>(fn: T, ms: number) => (...args: Parameters<T>) => void;
  throttle: <T extends (...args: unknown[]) => unknown>(fn: T, ms: number) => (...args: Parameters<T>) => void;
}

export interface Logger {
  info: (message: string, data?: Record<string, unknown>) => void;
  warn: (message: string, data?: Record<string, unknown>) => void;
  error: (message: string, data?: Record<string, unknown>) => void;
  debug: (message: string, data?: Record<string, unknown>) => void;
